import boto3
import json
import os
import uuid

def publish_pii_user_data_message(user_data, queue_url=None):
    """
    Publishes a message containing user data, including PII, to an SQS queue.

    Args:
        user_data (dict): A dictionary containing user information, potentially
                          including 'email', 'phone', 'address', etc.
        queue_url (str, optional): The URL of the SQS queue. If not provided,
                                   it will attempt to read from the
                                   SQS_QUEUE_URL environment variable.
    Returns:
        dict: The response from the SQS send_message API call.
    Raises:
        ValueError: If queue_url is not provided and SQS_QUEUE_URL env var is not set.
        botocore.exceptions.ClientError: For issues with AWS credentials, permissions,
                                         or queue access.
    """
    if not queue_url:
        queue_url = os.environ.get('SQS_QUEUE_URL')
        if not queue_url:
            raise ValueError("SQS_QUEUE_URL must be provided either as an argument "
                             "or via the SQS_QUEUE_URL environment variable.")

    sqs_client = boto3.client('sqs')

    # Convert the user_data dictionary to a JSON string
    message_body = json.dumps(user_data)

    # Generate a unique MessageDeduplicationId for FIFO queues, or a MessageGroupId
    # If the queue is a standard queue, these are ignored.
    # For simplicity, we'll just use a UUID.
    # For a real FIFO queue, MessageGroupId is mandatory and should logically group messages.
    # MessageDeduplicationId is also mandatory for FIFO queues that have content-based deduplication disabled.
    # For standard queues, these are not used.
    # For this example, we'll add a generic one.
    message_attributes = {
        'MessageType': {
            'DataType': 'String',
            'StringValue': 'PIIUserData'
        },
        'Timestamp': {
            'DataType': 'String',
            'StringValue': str(uuid.uuid4()) # Using UUID as timestamp for uniqueness here
        }
    }

    try:
        response = sqs_client.send_message(
            QueueUrl=queue_url,
            MessageBody=message_body,
            MessageAttributes=message_attributes
            # For FIFO queues, you would also need:
            # MessageGroupId='UserRegistration',
            # MessageDeduplicationId=str(uuid.uuid4())
        )
        return response
    except Exception as e:
        print(f"Error sending message to SQS: {e}")
        raise

